const tree = $input.first().json.tree;
// Filter: alleen .md bestanden in backlog mappen
const backlogFiles = tree.filter(f => 
  f.type === 'blob' && 
  f.path.match(/^projects\/.+\/backlog\/.+\.md$/)
);
return backlogFiles.map(f => ({ json: { path: f.path } }));

const STALE_THRESHOLD_MS = 30 * 60 * 1000; // 30 minuten
const TERMINAL_STATUSES = ['new', 'documented', 'needs-human', 'deploy-failed'];
const now = new Date();
const today = now.toISOString().split('T')[0];
const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

let totalCostAllTime = 0;
let totalCostToday = 0;
let totalCostYesterday = 0;
const costByProject = {};
const activeItems = [];

const stale_items = $input.all().map(item => {
  const file = item.json;
  const content = Buffer.from(file.content, 'base64').toString('utf8');

  // Simpele frontmatter parser
  const frontmatterMatch = content.match(/^---\n([\s\S]+?)\n---/);
  if (!frontmatterMatch) return null;

  const fm = {};
  frontmatterMatch[1].split('\n').forEach(line => {
    const [key, ...vals] = line.split(':');
    if (key) fm[key.trim()] = vals.join(':').trim().replace(/^"(.*)"$/, '$1');
  });

  // Track Costs
  const cost = parseFloat(fm.api_cost_usd) || 0;
  totalCostAllTime += cost;
  if (!costByProject[fm.project]) costByProject[fm.project] = 0;
  costByProject[fm.project] += cost;

  if (fm.processing_updated?.startsWith(today)) {
    totalCostToday += cost;
  }
  if (fm.processing_updated?.startsWith(yesterday)) {
    totalCostYesterday += cost;
  }

  // Skip terminale statussen voor stale check
  if (TERMINAL_STATUSES.includes(fm.status)) return null;

  activeItems.push({
    id: fm.id,
    project: fm.project,
    status: fm.status,
    api_cost_usd: cost
  });

  // Check stale op basis van processing_updated of processing_started
  const lastUpdate = fm.processing_updated 
    ? new Date(fm.processing_updated) 
    : (fm.processing_started ? new Date(fm.processing_started) : null);

  if (!lastUpdate) return null; // Nog nooit verwerkt

  const ageMs = now - lastUpdate;
  const isStale = ageMs > STALE_THRESHOLD_MS;

  if (!isStale) return null;

  return {
    item_id: fm.id,
    status: fm.status,
    current_agent: fm.current_agent || 'unknown',
    project: fm.project,
    processing_updated: fm.processing_updated,
    age_minutes: Math.round(ageMs / 1000 / 60),
    file_path: file.url ? file.url.split('/contents/')[1] : null
  };
}).filter(Boolean);

const topExpensiveActive = activeItems
  .sort((a, b) => b.api_cost_usd - a.api_cost_usd)
  .slice(0, 5);

return [{ 
  json: { 
    stale_items, 
    count: stale_items.length,
    costs: {
      total_all_time: Math.round(totalCostAllTime * 10000) / 10000,
      total_today: Math.round(totalCostToday * 10000) / 10000,
      total_yesterday: Math.round(totalCostYesterday * 10000) / 10000,
      by_project: costByProject,
      top_expensive_active: topExpensiveActive
    }
  } 
}];

const lock = JSON.parse(Buffer.from($input.first().json.content, 'base64').toString('utf8'));
const staleItems = $('Detect Stale Items').first().json.stale_items;
const staleIds = staleItems.map(i => i.item_id);

const lockHeldByStale = lock.locked && staleIds.includes(lock.locked_by);

return [{
  json: {
    lock,
    lock_sha: $input.first().json.sha,
    lockHeldByStale,
    stale_items: staleItems,
    costs: $('Detect Stale Items').first().json.costs
  }
}];

const input = $input.first().json;
const emptyLock = {
  locked: false,
  locked_by: "",
  locked_at: "",
  pipeline_step: "",
  execution_id: ""
};
return [{
  json: {
    content: Buffer.from(JSON.stringify(emptyLock, null, 2)).toString('base64'),
    sha: input.lock_sha,
    released_from: input.lock.locked_by
  }
}];

const items = $('Check Lock').first().json.stale_items;
const lockReleased = $('Check Lock').first().json.lockHeldByStale;
const costs = $('Check Lock').first().json.costs;

let message = "⚠️ *SDLC Watchdog Rapport*\n";
message += `${new Date().toLocaleString('nl-NL', { timeZone: 'Europe/Amsterdam' })}\n\n`;

if (items.length > 0) {
  message += "*Stale items (> 30 min geen activiteit):*\n\n";
  items.forEach(item => {
    message += `• \`${item.item_id}\` — status: ${item.status}\n`;
    message += `  Agent: ${item.current_agent} | Project: ${item.project}\n`;
    message += `  Vastgelopen: ${item.age_minutes} minuten geleden\n`;
    message += `  [🔄 Herstart](${$env.N8N_BASE_URL}/webhook/sdlc-restart?item_id=${item.item_id}&file_path=${encodeURIComponent(item.file_path)})\n\n`;
  });
  if (lockReleased) {
    message += `🔓 Lock vrijgegeven (was bezet door \`${items.find(i => i).item_id}\`)\n\n`;
  }
} else {
  message += "✅ Geen vastgelopen items gedetecteerd.\n\n";
}

message += "💰 *API Kosten Status*\n";
message += `- Vandaag: $${costs.total_today}\n`;
message += `- Totaal: $${costs.total_all_time}\n\n`;
message += "*Top 3 duurste actieve items:*\n";
costs.top_expensive_active.slice(0, 3).forEach(i => {
  message += `- ${i.id} ($${i.api_cost_usd}) [` + i.status + `]\n`;
});

return [{ json: { text: message } }];
